insert into public.bilateral_dossiers
  (id, campaign_id, faction_a_id, faction_b_id, pair_name, canon_core, a_to_b, b_to_a, common_interest, fracture, triggers, scene_hook, evidence_note)
values
  ('00000000-0000-4000-8400-000000000001','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000101','00000000-0000-4000-8100-000000000102','Bâtisseurs ↔ Célébrants','Célébrants : ennemi déclaré. Secrets et passages cachés contre maîtrise du récit public.','La Ligue traite la communication comme une fuite et cherche à contrôler plans et accès.','Les Célébrants voient chaque secret comme un récit abandonné à un rival.','Monuments, processions, inaugurations et restauration prestigieuse.','Qui décide ce que le public voit et ce que l’ouvrage dissimule ?','Salle cachée ; fuite de plans ; cérémonie retardée ; faiblesse révélée.','Inaugurer un monument dont la Ligue veut condamner la crypte et que les Célébrants veulent ouvrir.','Explicite côté Célébrants ; synthèse côté Ligue.'),
  ('00000000-0000-4000-8400-000000000002','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000101','00000000-0000-4000-8100-000000000103','Bâtisseurs ↔ Exportation','La Ligue nomme la Guilde ennemie : étrangers et richesse menacent ses secrets.','Contre-espionnage, permis, contrôle des plans et des infrastructures.','La Guilde subit retards et coûts imposés par des traditionalistes.','Ports, entrepôts, routes, quarantaine et production déplacée hors de vue.','Vitesse et capacité contre contrôle et secret.','Inspecteur étranger ; autorisation bloquée ; tunnel ; sabotage attribué.','Concevoir un complexe souterrain : la Guilde impose le délai, la Ligue conserve les plans.','Hostilité explicite ; coopération pragmatique synthétique.'),
  ('00000000-0000-4000-8400-000000000003','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000101','00000000-0000-4000-8100-000000000104','Bâtisseurs ↔ Réanimateurs','Alliance explicite côté Bâtisseurs ; la main-d’œuvre morte-vivante est indispensable aux grands travaux.','La Ligue contrôle plans, permis, accès et affectation du chantier.','Les Réanimateurs veulent que leur travail, leurs corps et leurs pertes soient reconnus.','Chantiers, infrastructures agricoles, sécurisation et récupération d’ouvriers.','Responsabilité, propriété des corps et accès aux zones secrètes.','Accident ; ouvriers détournés ; ossuaire découvert ; ordres contradictoires.','Un effondrement révèle des corps réclamés sous un ouvrage que la Ligue veut cacher.','Alliance explicite et synthèse de leurs domaines.'),
  ('00000000-0000-4000-8400-000000000004','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000101','00000000-0000-4000-8100-000000000105','Bâtisseurs ↔ UCI','L’UCI nomme la Ligue alliée ; tradition, caveaux et structures impénétrables.','La Ligue conçoit, autorise et garde les secrets techniques.','L’UCI finance, possède, taxe et saisit.','Banques, coffres, immobilier, péages et reconstruction.','Propriété du projet, copie des plans et dépassement de coût.','Défaut ; audit ; titre ancien ; plan copié ; permis lié à un prêt.','Deux contrats concurrents rouvrent une banque : propriété à l’UCI ou contrôle technique à la Ligue.','Alliance explicite côté UCI.'),
  ('00000000-0000-4000-8400-000000000005','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000101','00000000-0000-4000-8100-000000000106','Bâtisseurs ↔ Charretiers','Routes et relais bâtis par la Ligue ; transport intérieur assuré par le Consortium.','La Ligue traite facilement la faction déchue comme exécutant remplaçable.','Les Charretiers vivent chaque route abandonnée comme le mépris des Grandes Factions.','Ponts, relais, convois, réparations et déviations.','Priorité des travaux, sécurité, péages et responsabilité.','Pont fermé ; route vendue ; relais réquisitionné ; village oublié.','Rouvrir la route de Pakged : permis complet ou réparation illégale avant la nuit.','Synthèse des domaines ; ressentiment optionnel.'),
  ('00000000-0000-4000-8400-000000000006','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000102','00000000-0000-4000-8100-000000000103','Célébrants ↔ Exportation','Partenariat officiel de vitrine ; la Guilde nomme les Célébrants alliés.','Les Célébrants contrôlent le récit, la cérémonie et la visibilité.','La Guilde contrôle invités, cargaisons et coût diplomatique.','Délégations, cérémonies portuaires, captifs informés et promotion nationale.','Spectacle contre discrétion et pragmatisme marchand.','Invité offensé ; captif disputé ; cargaison indigne ; vérité gênante.','Accueillir un émissaire : accord discret ou procession qui expose tout.','Alliance explicite et arrangement fonctionnel.'),
  ('00000000-0000-4000-8400-000000000007','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000102','00000000-0000-4000-8100-000000000104','Célébrants ↔ Réanimateurs','Normalisation de la non-vie par le récit d’un côté, production de l’autre.','Les Célébrants peuvent glorifier ou cacher le travail nécromantique.','Les Réanimateurs gagnent en légitimité mais refusent d’être le fusible d’un scandale.','Fêtes des récoltes, cérémonies d’animation et démonstrations de prospérité.','Réalité industrielle macabre contre récit héroïque.','Corps mal acquis ; accident visible ; pénurie ; dispute doctrinale.','Banquet de récolte pendant un problème de contrôle des travailleurs exposé au public.','Synthèse forte seulement.'),
  ('00000000-0000-4000-8400-000000000008','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000102','00000000-0000-4000-8100-000000000105','Célébrants ↔ UCI','Ennemis déclarés ; accès autonome aux coffres, dépenses et ascension contre statu quo.','Les Célébrants convertissent l’argent en visibilité et influence.','L’UCI voit gaspillage, perte de contrôle et menace sur le prestige ancien.','Cérémonies, démonstrations de richesse et taxes sur événements.','Budget, autonomie, audit et ancienneté.','Dépassement ; don ostentatoire ; contrôle surprise ; saisie d’accessoires.','Financer une procession : crédit immédiat contre audit public humiliant.','Inimitié explicite.'),
  ('00000000-0000-4000-8400-000000000009','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000102','00000000-0000-4000-8100-000000000106','Célébrants ↔ Charretiers','Faction déchue après le scandale pharasméen ; les Célébrants contrôlent l’image publique.','Les Célébrants peuvent réhabiliter le Consortium ou raviver le scandale.','Les Charretiers offrent mobilisation, courrier et transport, mais craignent la publicité.','Processions, déplacement de foules, matériel et rumeurs.','Passé pharasméen et secret logistique contre visibilité.','Vieille preuve ; conducteur indiscret ; convoi retardé ; loyauté exigée.','Le manifeste d’une procession révèle une ancienne route liée au scandale.','Disgrâce explicite ; réhabilitation optionnelle.'),
  ('00000000-0000-4000-8400-000000000010','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000103','00000000-0000-4000-8100-000000000104','Exportation ↔ Réanimateurs','Asymétrie officielle : ennemi côté Exportation, allié côté Réanimateurs ; dépendance économique majeure.','La Guilde veut cacher ou déplacer ce qui effraie ses partenaires.','Les Réanimateurs ont besoin des débouchés mais refusent d’être traités comme une honte.','Récoltes, travail, transport de masse, revenus et grands projets.','Image, emplacement des fermes, conditions et partage de la valeur.','Visite étrangère ; boycott ; cargaison contaminée ; déplacement forcé.','Déplacer la production hors de vue, avec financement, chantier et propagande.','Relation pivot explicitement détaillée.'),
  ('00000000-0000-4000-8400-000000000011','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000103','00000000-0000-4000-8100-000000000105','Exportation ↔ UCI','Flux et profits rencontrent financement, taxes et surveillance.','La Guilde investit vite et accepte le risque commercial.','L’UCI veut rendement garanti, perception et stabilité.','Crédit commercial, assurance, douanes et investissement portuaire.','Ouverture contre prudence ; liquidité contre thésaurisation.','Défaut ; saisie ; crédit refusé ; taxe nouvelle ; capital étranger.','Importer un bien stratégique : ouverture décisive contre garantie impossible.','Synthèse de leurs actifs et orientations.'),
  ('00000000-0000-4000-8400-000000000012','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000103','00000000-0000-4000-8100-000000000106','Exportation ↔ Charretiers','Commerce extérieur et transport intérieur forment une chaîne sans alliance déclarée.','La Guilde contrôle port, client étranger et documents d’entrée.','Les Charretiers contrôlent le dernier trajet, les routes et la discrétion intérieure.','Transbordement, manifestes, entrepôts et convois.','Juridiction, marges, contrebande et responsabilité.','Faux manifeste ; embargo ; route secrète ; cargaison suspecte.','Une cargaison légale au port devient compromettante à l’intérieur.','Synthèse des domaines et de la juridiction.'),
  ('00000000-0000-4000-8400-000000000013','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000104','00000000-0000-4000-8100-000000000105','Réanimateurs ↔ UCI','Ennemis déclarés côté Réanimateurs : taxes lourdes et mépris du travail productif.','Les Réanimateurs revendiquent la richesse créée et la continuité de l’approvisionnement.','L’UCI taxe, surveille et peut redouter cette immense force de travail.','Revenus agricoles, inventaires, contrats et infrastructure rurale.','Taxation, statut des corps, valeur du travail et saisie d’actifs.','Audit ; saisie d’ouvriers ; taxe d’urgence ; fraude ; pénurie.','Saisir une équipe pour arriérés fiscaux pendant une récolte critique.','Inimitié explicite et synthèse économique.'),
  ('00000000-0000-4000-8400-000000000014','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000104','00000000-0000-4000-8100-000000000106','Réanimateurs ↔ Charretiers','Production cadavérique et agricole contre transport intérieur.','Les Réanimateurs exigent conformité, fiabilité et respect de la propriété des corps.','Les Charretiers assument un risque qu’ils ne comprennent pas toujours, sous soupçon pharasméen.','Convois agricoles, corps, matériel et travailleurs.','Propriété, manifestes, cargaisons animées et confiance.','Corps volé ; cargaison animée ; chauffeur ignorant ; sabotage religieux.','Un manifeste dit « outils agricoles » mais une partie est juridiquement une dépouille.','Synthèse des domaines et du passé du Consortium.'),
  ('00000000-0000-4000-8400-000000000015','00000000-0000-4000-8000-000000000001','00000000-0000-4000-8100-000000000105','00000000-0000-4000-8100-000000000106','UCI ↔ Charretiers','Taxes, crédit, transport et relais contre ancienne Grande Faction déchue.','L’UCI traite le Consortium comme débiteur, contribuable et outil logistique.','Les Charretiers ressentent péages et tutelle mais ont besoin de crédit et de reconnaissance.','Péages, financement, assurance, saisies et relais.','Dette, autonomie et contrôle des flux.','Hausse de péage ; saisie ; audit ; dette ancienne ; reprise de contrôle.','Financer un relais contre l’abandon de l’autonomie sur la meilleure route.','Statut et actifs explicites ; créancier optionnel.');
